import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, "..", "..");

function generatedBanner(moduleRelativePath, runScriptName) {
  return [
    "// AUTO-GENERATED FILE.",
    `// Source: ${moduleRelativePath}`,
    `// Run: npm run ${runScriptName}`,
    "// Do not edit this file directly.",
    "",
  ].join("\n");
}

export async function generateClassicBridge({
  moduleRelativePath,
  classicRelativePath,
  runScriptName,
  transform = (source) => source,
  tail = "",
  write = true,
}) {
  const modulePath = path.join(repoRoot, moduleRelativePath);
  const classicPath = path.join(repoRoot, classicRelativePath);
  const moduleSource = await fs.readFile(modulePath, "utf8");
  const bridgeSource = transform(moduleSource);
  const output = `${generatedBanner(moduleRelativePath, runScriptName)}${bridgeSource}${tail}`;
  if (write) {
    await fs.writeFile(classicPath, output, "utf8");
  }
  return {
    classicPath,
    output,
  };
}
